@rendermode InteractiveServer
@using sv_6ae0adae234540a2bcf3c07a081975c6.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="chat-sidebar">
        <div class="sidebar-header">
            <h5>Channels</h5>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="badge bg-primary unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="chat-main @(threadOpen ? "" : "chat-main-wide")">
        @if (activeChannel is not null)
        {
            <div class="main-header">
                <h5># @activeChannel.Name</h5>
                <span class="text-muted">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (loadingOlder)
                {
                    <div class="text-center p-2"><em>Loading older messages…</em></div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                            <div class="message-header">
                                <strong>@msg.Author</strong>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <span class="reaction-badge" title="@string.Join(", ", r.Users)"
                                              @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </span>
                                    }
                                </div>
                            }

                            @{ var summary = GetThreadSummary(msg); }
                            @if (summary is not null)
                            {
                                <button class="btn btn-link btn-sm thread-link p-0"
                                        @onclick="() => OpenThreadAsync(msg.Id)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }

                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="btn btn-sm btn-outline-secondary" title="Reply"
                                            @onclick="() => OpenThreadAsync(msg.Id)">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="btn btn-sm btn-outline-secondary" title="React"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀
                                        </button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-btn"
                                                            @onclick="() => PickEmojiAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="form-control" rows="2" placeholder="Type a message…"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown"></textarea>
                <button class="btn btn-primary" disabled="@string.IsNullOrWhiteSpace(newMessageText)"
                        @onclick="SendMainMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <em>Select a channel to start chatting</em>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadOpen)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h6>Thread</h6>
                <button class="btn btn-sm btn-close" @onclick="CloseThread"></button>
            </div>

            @if (threadRootMessage is not null)
            {
                <div class="thread-root-quote">
                    <strong>@threadRootMessage.Author</strong>
                    <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                    <p>@threadRootMessage.Content</p>
                </div>
            }

            <div class="thread-replies">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-row">
                            <div class="message-header">
                                <strong>@reply.Author</strong>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="form-control" rows="2" placeholder="Reply in thread…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown"></textarea>
                <button class="btn btn-primary" disabled="@string.IsNullOrWhiteSpace(threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel>? channels;
    private int? activeChannelId;
    private Channel? activeChannel;
    private List<Message>? messages;
    private string newMessageText = "";
    private int? hoveredMessageId;

    // Pagination
    private const int PageSize = 30;
    private int currentSkip;
    private bool loadingOlder;
    private bool hasMoreOlder = true;
    private ElementReference messageListRef;

    // Thread panel
    private bool threadOpen;
    private int? threadRootId;
    private Message? threadRootMessage;
    private List<Message>? threadMessages;
    private string threadReplyText = "";

    // Emoji picker
    private int? emojiPickerMessageId;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // Thread summaries keyed by root message id
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (activeChannelId == channel.Id) return;

        activeChannelId = channel.Id;
        activeChannel = channel;
        currentSkip = 0;
        hasMoreOlder = true;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh unread badge
        channels = await ChatService.GetChannelsAsync();

        // Scroll to bottom after render
        await ScrollToBottom();
    }

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, newMessageText.Trim(), null);
        newMessageText = "";
        messages ??= new();
        messages.Add(sent);
        await ScrollToBottom();
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Scroll & pagination ──

    private async Task OnMessageListScroll()
    {
        if (loadingOlder || !hasMoreOlder || activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (activeChannelId is null) return;
        loadingOlder = true;
        currentSkip += PageSize;

        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, currentSkip, PageSize);
        if (older.Count < PageSize) hasMoreOlder = false;
        if (older.Count > 0)
        {
            messages = older.Concat(messages ?? Enumerable.Empty<Message>()).ToList();
            BuildThreadSummaries();
        }

        loadingOlder = false;
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield(); // let Blazor render first
        await JS.InvokeVoidAsync("eval", "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    // ── Thread panel ──

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootId = rootMessageId;
        threadRootMessage = messages?.FirstOrDefault(m => m.Id == rootMessageId);
        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyText = "";
        threadOpen = true;
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootId = null;
        threadRootMessage = null;
        threadMessages = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootId is null || activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, threadReplyText.Trim(), threadRootId);
        threadReplyText = "";
        threadMessages ??= new();
        threadMessages.Add(reply);
        BuildThreadSummaries();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions & emoji picker ──

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task PickEmojiAsync(int messageId, string emoji)
    {
        emojiPickerMessageId = null;
        await ToggleReactionAsync(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to show updated reaction counts
        if (activeChannelId is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, currentSkip + PageSize);
            BuildThreadSummaries();
        }
    }

    // ── Helpers ──

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private ThreadSummary? GetThreadSummary(Message msg)
    {
        return msg.ReplyToId is null && threadSummaries.TryGetValue(msg.Id, out var s) ? s : null;
    }

    private static string Truncate(string text, int maxLen)
        => text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}
"}

